#include <stdio.h>
#include <stdlib.h>
int main(){
    int N;
    if(scanf("%d", &N)!=1) return 0;
    for(int i=0;i<N;++i){
        long long P,T,R;
        if(scanf("%lld %lld %lld", &P, &T, &R)!=3) return 0;
        double si = (P * (double)T * (double)R) / 100.0;
        printf("%.1f\n", si);
    }
    return 0;
}

